script:
function setupForm({ doc, call, toast, $dialog }) {

    const actions = []

    // Cross-sell Lead button
    actions.push({
        label: "Create Cross Sell Lead",
        onClick: () => {
            $dialog({
                title: "Create Cross Sell Lead",
                fields: [
                    {
                        label: "Entity",
                        fieldname: "entity",
                        fieldtype: "Select",
                        options: ["Aionion Capital", "Aionion Insurance", "US Subscription"],
                        reqd: 1
                    },
                    {
                        label: "Product",
                        fieldname: "product",
                        fieldtype: "Select",
                        options: ["Account Opening", "Bonds", "Mutual Funds", "Insurance Sales", "Insurance Renewals", "US Subscription"],
                        reqd: 1
                    }
                ],
                actions: [{
                    label: "Create Lead",
                    variant: "solid",
                    onClick: (close, values) => {
                        if (!values || !values.entity || !values.product) {
                            toast.error("Please select Entity and Product")
                            return
                        }
                        call(
                            "aionion_custom.aionion_custom.controllers.customer.create_cross_sell_lead",
                            { customer_name: doc.name, entity: values.entity, product: values.product }
                        ).then((r) => {
                            close()
                            toast.success("Cross-sell lead created: " + r)
                        }).catch((e) => {
                            close()
                            toast.error(e.message || "Error creating lead")
                        })
                    }
                }]
            })
        }
    })

    // Assigned Products button
    actions.push({
        label: "View Products",
        onClick: () => {
            call(
                "aionion_custom.aionion_custom.controllers.customer.get_customer_products",
                { customer_name: doc.name }
            ).then((products) => {
                if (!products || products.length === 0) {
                    toast.success("No products found for this customer")
                    return
                }
                let html = "<table style='width:100%;border-collapse:collapse'>"
                html += "<tr style='background:#f5f5f5'><th style='padding:8px;border:1px solid #ddd'>Type</th><th style='padding:8px;border:1px solid #ddd'>Product</th><th style='padding:8px;border:1px solid #ddd'>Status</th><th style='padding:8px;border:1px solid #ddd'>Reference</th></tr>"
                products.forEach(p => {
                    html += "<tr>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + p.type + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.product || "") + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.status || "") + "</td>"
                    html += "<td style='padding:8px;border:1px solid #ddd'>" + (p.reference || p.record || "") + "</td>"
                    html += "</tr>"
                })
                html += "</table>"
                $dialog({
                    title: "Assigned Products (" + products.length + ")",
                    html: html,
                    actions: []
                })
            }).catch((e) => {
                toast.error(e.message || "Error fetching products")
            })
        }
    })

    return { actions }
}

function setupList() {
  return {
    actions: [
      {
        label: "Customers",
        onClick: () => {
          window.open("/app/customer", "_blank");
        },
      },
      {
        label: "Tasks",
        onClick: () => {
          window.open("/app/aionion-task", "_blank");
        },
      },
    ],
  };
}

function setupForm({ doc, call, toast, $dialog }) {

    if (doc.custom_entity !== "Aionion Insurance") return

    const actions = []

    // Hide the Assign To button — assignment managed by our system only
    setTimeout(() => {
        // Hide assignees button in CRM
        const assignBtn = document.querySelector('.assignees')
        if (assignBtn) assignBtn.style.display = 'none'

        // Also hide via CSS
        const style = document.createElement('style')
        style.textContent = '.assignees { display: none !important; } .assignments { display: none !important; }'
        document.head.appendChild(style)
    }, 500)



    // Assign Service RM button — draft leads without Service RM
    if ((!doc.docstatus || doc.docstatus === 0) && !doc.custom_service_rm) {
        actions.push({
            label: "Assign Service RM",
            onClick: () => {
                call(
                    "aionion_custom.aionion_custom.controllers.crm_lead.get_suggested_service_rm",
                    { lead_name: doc.name }
                ).then((suggestion) => {
                    $dialog({
                        title: "Assign Service RM",
                        message: "Suggested: " + (suggestion.service_rm_name || "None") + " | " + (suggestion.reason || ""),
                        actions: [{
                            label: "Confirm & Assign",
                            variant: "solid",
                            onClick: (close) => {
                                if (!suggestion.service_rm) {
                                    toast.error("No Service RM available")
                                    close()
                                    return
                                }
                                call(
                                    "aionion_custom.aionion_custom.controllers.crm_lead.assign_service_rm",
                                    { lead_name: doc.name, service_rm: suggestion.service_rm }
                                ).then(() => {
                                    close()
                                    toast.success("Service RM assigned: " + suggestion.service_rm_name)
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => {
                                    close()
                                    toast.error(e.message || "Error assigning Service RM")
                                })
                            }
                        }]
                    })
                }).catch((e) => {
                    toast.error(e.message || "Error getting suggestion")
                })
            }
        })
    }

    // Submit Lead button — draft leads
    if (!doc.docstatus || doc.docstatus === 0) {
        actions.push({
            label: "Submit Lead",
            onClick: () => {
                if (!doc.custom_policy_status) {
                    toast.error("Please set Policy Status before submitting.")
                    return
                }
                if (doc.custom_policy_status === "Issued" && !doc.custom_policy_number) {
                    toast.error("Policy Number is mandatory when Policy Status is Issued.")
                    return
                }
                $dialog({
                    title: "Submit Lead",
                    message: "Are you sure? Lead will be locked after submission.",
                    actions: [{
                        label: "Submit",
                        variant: "solid",
                        onClick: (close) => {
                            call(
                                "aionion_custom.aionion_custom.controllers.crm_lead.submit_insurance_lead",
                                { lead_name: doc.name }
                            ).then(() => {
                                close()
                                toast.success("Lead submitted! MIS team will now verify.")
                                setTimeout(() => window.location.href = window.location.href, 1500)
                            }).catch((e) => {
                                close()
                                toast.error(e.message || "Something went wrong")
                            })
                        }
                    }]
                })
            }
        })
    }

    // MIS buttons — ONLY for Insurance MIS role users on submitted leads
    if (doc.docstatus === 1) {
        call(
            "aionion_custom.aionion_custom.controllers.crm_lead.check_mis_role",
            {}
        ).then((has_role) => {
            if (!has_role) return
            // This won't work in actions pattern — MIS buttons added separately below
        })
    }

    return { actions }
}

function setupForm({ doc, call, toast, $dialog }) {
    if (doc.custom_entity !== "Aionion Insurance") return
    if (doc.docstatus !== 1) return
    if (doc.custom_product === "Insurance Renewals") return

    const actions = []

    // Fetch roles from server — more reliable than frappe.user_roles
    call("aionion_custom.aionion_custom.controllers.crm_lead.get_current_user_roles", {})
    .then((roles) => {
        const isMIS = roles.includes("Insurance MIS") || roles.includes("System Manager")
        if (!isMIS) return

        if (doc.custom_mis_status !== "Approved") {
            actions.push({
                label: "Verify MIS",
                onClick: () => {
                    $dialog({
                        title: "Verify MIS",
                        message: "Have you verified Policy No " + (doc.custom_policy_number || "N/A") + " in the insurer portal?",
                        actions: [{
                            label: "Verify",
                            variant: "solid",
                            onClick: (close) => {
                                call(
                                    "aionion_custom.aionion_custom.controllers.crm_lead.approve_mis",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("MIS Verified!")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Error") })
                            }
                        }]
                    })
                }
            })
        }

        if (doc.custom_mis_status !== "Rejected") {
            actions.push({
                label: "Reject MIS",
                onClick: () => {
                    $dialog({
                        title: "Reject MIS",
                        message: "Reject MIS for " + doc.lead_name + "? Lead will be unlocked for Service RM to refill.",
                        actions: [{
                            label: "Reject",
                            variant: "solid",
                            onClick: (close) => {
                                call(
                                    "aionion_custom.aionion_custom.controllers.crm_lead.reject_mis",
                                    { lead_name: doc.name }
                                ).then(() => {
                                    close()
                                    toast.success("MIS Rejected. Lead unlocked.")
                                    setTimeout(() => window.location.href = window.location.href, 1500)
                                }).catch((e) => { close(); toast.error(e.message || "Error") })
                            }
                        }]
                    })
                }
            })
        }

        // Force re-render actions
        return { actions }
    })

    return { actions }
}
